        return False
    arr = output
    for v in arr:
        if not isinstance(v, int) or isinstance(v, bool) or v <= 0:
            return False
    from collections import Counter
    nums_cnt = Counter(nums)
    a0 = arr[0]
    candidates = set()
    for nv in nums:
        diff = nv - a0
        if diff != 0:
            candidates.add(abs(diff))
    for k in candidates:
