import bisect


class Solution:
    def recoverArray(self, nums):
        s = sorted(nums)
        n = len(s) // 2
        for i in range(1, len(s)):
            diff = s[i] - s[0]
            if diff <= 0 or diff % 2 != 0:
                continue
            k = diff // 2
            pool = list(s)
            arr = []
            ok = True
            while pool:
                v = pool[0]
                partner = v + 2 * k
                pos = bisect.bisect_left(pool, partner)
                if pos >= len(pool) or pool[pos] != partner or pos == 0:
                    ok = False
                    break
                del pool[pos]
                arr.append(v + k)
                del pool[0]
            if ok and len(arr) == n:
                return sorted(arr)
        return []

