from collections import Counter


class Solution:
    def recoverArray(self, nums):
        s = sorted(nums)
        n = len(s) // 2
        for i in range(1, len(s)):
            diff = s[i] - s[0]
            if diff <= 0 or diff % 2 != 0:
                continue
            k = diff // 2
            cnt = Counter(s)
            arr = []
            ok = True
            for v in s:
                if cnt[v] <= 0:
                    continue
                partner = v + 2 * k
                if cnt[partner] <= 0:
                    ok = False
                    break
                cnt[v] -= 1
                cnt[partner] -= 1
                arr.append(v + k)
            if ok and len(arr) == n:
                return sorted(arr)
        return []

