var recoverArray = function(nums) {
    const s = nums.slice().sort((a, b) => a - b);
    const n = s.length / 2;
    for (let i = 1; i < s.length; i++) {
        const diff = s[i] - s[0];
        if (diff <= 0 || diff % 2 !== 0) continue;
        const k = diff / 2;
        const cnt = new Map();
        for (const v of s) cnt.set(v, (cnt.get(v) || 0) + 1);
        const arr = [];
        let ok = true;
        for (const v of s) {
            if ((cnt.get(v) || 0) <= 0) continue;
            const partner = v + 2 * k;
            if ((cnt.get(partner) || 0) <= 0) { ok = false; break; }
            cnt.set(v, cnt.get(v) - 1);
            cnt.set(partner, cnt.get(partner) - 1);
            arr.push(v + k);
        }
        if (ok && arr.length === n) {
            arr.sort((a, b) => a - b);
            return arr;
        }
    }
    return [];
};
